const Q_COMMERCE_2007=[{"id": "objective>Commerce>2007>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consumers require protection against exploitation to ensure </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adequate consumer awareness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of product variety</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the sales of quality products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased aggregate demand</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consumers require protection against exploitation to ensure the sales of quality products. In Nigeria, the Consumer Protection Council (CPC) is responsible for this. Consumer Protection Council (CPC) is a parastatal of the Federal Government of Nigeria, supervised by the Federal Ministry of Trade and Investment. <br/>  Its mandate requires it to, among others, eliminate hazardous products from the market, provide speedy redress to consumers complaints, undertake campaigns as will lead to increased consumer awareness, ensure that consumers interest receive due consideration at the appropriate forum, and encourage trade, industry and professional associations to develop and enforce in their various fields quality standards designed to safeguard the interest of consumers.</div>", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : CONSUMER PROTECTION"}, {"id": "objective>Commerce>2007>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The business environment that takes into cognizance the age distribution, ethnic mix and educational level of the consumer is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demographic environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cultural environment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural environment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Demographic environment: This is a study of perspective of population i.e. its size, standard of living, growth rate, age-sex composition, family size, income level etc.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : FACTORS"}, {"id": "objective>Commerce>2007>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An agent who takes title to goods and has authority to buy and sell on behalf of another is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a jobber</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a broker</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a factor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an auctioneer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A factor is an agent entrusted with the possession of goods for the purpose of sale. A factor has authority to sell goods in his own name and receives the purchase price.</div>", "topic": "LEGAL ASPECT OF BUSINESS: SALES OF GOODS ACT : AGENCY IN SALES OF GOODS ACT"}, {"id": "objective>Commerce>2007>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Citizens are against privatization mainly because of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the rationalization of organization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase price of goods and services </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the likelihood of monopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ineffective management </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The disadvantages of privatisation are: <br/> - poor standard of living <br/> - high cost of products <br/> - reduction in employment <br/> - to generate more revenue <br/> - autonomy of enterprises <br/> - removal of unproductive enterprises</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVATAGES"}, {"id": "objective>Commerce>2007>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major achievement of ECOWAS is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the expansion of regional trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the emergence of monetary union </div>", "<div style=\"font-family:Cambria;font-size:17px;\">infrastructural development in member countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mobilization of labour among member countries</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Economic Community of West African States is a regional group of fifteen West African countries. The organization was founded in order to achieve <strong>collective self-sufficiency</strong> for its member states by creating a single large trading bloc through an economic and trading union. </div>", "topic": "ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC."}, {"id": "objective>Commerce>2007>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An announcement of a person's willingness to enter into a contract is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a proxy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an offer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a consideration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an acceptance</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When someone expresses his or her willingness to enter into a contract on certain terms and intends to form a binding contract if the other party accepts it, such expression of willingness is called an offer.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : MEANING AND TYPES OF CONTRACT"}, {"id": "objective>Commerce>2007>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The micro-environmental forces and trends which are a constraint on business operations are refered to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">technical factors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic factors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">external factor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">internal factors</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">External environment are factors which are beyond the control of business organization. These factors are: government and legal factors, geographical factors, political factors, socio-cultural factors, demo-graphical factors etc. </div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : FACTORS"}, {"id": "objective>Commerce>2007>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following describes inputs for any production activity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Natural resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Business resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Human resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Material resources</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Natural resources: These are raw materials obtained from nature that are used in production, such as minerals, water, and land. <br/>  <br/> Business resources: This term can encompass all types of resources (natural, human, and material) used in business activities. <br/>  <br/> Human resources: This includes the labor, skills, and expertise provided by people that contribute to the production process. <br/>  <br/> Material resources: These are physical items used in production, such as raw materials and machinery. <br/>  <br/> In a more focused context, the answer might be more specific: <br/> - If the question is asking for a general term that encompasses all inputs, then Business resources is correct. <br/>  <br/> -  If the question is focusing on the different types of specific inputs, then natural, human and material are all correct in their respective contexts. <br/>  <br/> Given the context of production activities, all these resources (natural, human, and material) are essential inputs. So, if choosing one encompassing term, Business resources is appropriate.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2007>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Personal selling is most effective in marketing industrial goods because it involves</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">recognition and attachment to customers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">personal interaction and information gathering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demonstrations and product acceptability </div>", "<div style=\"font-family:Cambria;font-size:17px;\">after-sales services and product demonstrations</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Personal selling is where businesses use people to sell the product after meeting face-to-face with the customer. The sellers promote the product through their attitude, appearance and specialist product knowledge.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>2007>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The controllable variables that a firm uses to achieve its marketing objectives are called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marketing principles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing mix</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing concept</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing functions</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marketing mix is the combination/collection of controllable variable/factors that can be used to influence the behaviour of customer (consumer).</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2007>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Public relations and Advertising are similar in terms of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">communicating product information </div>", "<div style=\"font-family:Cambria;font-size:17px;\">customer's education </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the mode of operation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">creating favourable attitude</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is because both public relations and advertising are designed to create a positive image of the organization and to promote its products or services. Public relations professionals use a variety of methods to achieve this goal, such as press releases, media relations, and events. Advertisers use a variety of media to reach their target audience, such as television, radio, print, and online. <br/>  <br/> While both public relations and advertising can be used to communicate product information and educate customers, their primary goal is to create a favorable attitude towards the organization, its products, or its services.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>2007>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major function of an entrepreneur is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decision-making</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encouraging competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">human resources training</div>", "<div style=\"font-family:Cambria;font-size:17px;\">motivating employees</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Entrepreneurs are often responsible for making significant decisions that affect the direction and success of their businesses. This can include decisions about product development, marketing strategies, and hiring and firing employees.</div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE"}, {"id": "objective>Commerce>2007>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A Memorandum of Association is applicable to a  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sole trader </div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint-stock company</div>", "<div style=\"font-family:Cambria;font-size:17px;\">partnership </div>", "<div style=\"font-family:Cambria;font-size:17px;\">public corporation </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Memorandum of Association is applicable to a joint-stock company. A Memorandum of Association (MOA) is a legal document prepared in the formation and registration process of a limited liability company to define its relationship with shareholders.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2007>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sustainable growth of commerce is largely due to  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marketing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">advertising </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">branding </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sustainable growth of commerce is largely due to exchange. Commerce is essentially about the exchange of goods and services, usually for money. Marketing, advertising, and branding are all important aspects of commerce, but they are means to facilitate exchange, not the core of commerce itself.</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>2007>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major advantage of a cooperative society is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gives member the opportunity to unite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">draws members closer to government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote awareness among members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourages thrift among members</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cooperative society encourages thrift among members. e.g saving and contributing, buying goods in bulk at cheaper prices to distribute to members.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVATAGES"}, {"id": "objective>Commerce>2007>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The making of doors from timber planks is a type of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manufacturing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tertiary production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary production </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary production is the manufacturing and assembly process. It involves converting raw materials into components, for example,  making plastics from oil. It also involves assembling the product e.g  building houses, bridges and roads.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2007>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Law-making is an example of  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indirect service </div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial occupation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrial occupation </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Law-making can be considered an indirect service because its primary function is to establish rules, regulations, and frameworks that govern society as a whole. <br/> It sets the legal framework and provides guidelines that indirectly benefit individuals and businesses by ensuring order, protection of rights, and resolution of disputes. <br/> Law-making does not directly provide a tangible product or service to individuals in the same way that healthcare or education does.</div>", "topic": "OCCUPATION : MEANING & IMPORTANCE"}, {"id": "objective>Commerce>2007>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A document which advertises the shares of a company is known as a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">memorandum of satisfaction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dividend warrant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prospectus</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is a printed booklet advertising a business to potential investors giving details of a share offer for the benefit of decision making.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2007>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The scope of economic activities can be enlarged by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transportation and trading </div>", "<div style=\"font-family:Cambria;font-size:17px;\">business and its promotion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">trading and aids to trade</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insurance and banking </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trading is the exchange of goods and services between two or more parties. It is the driving force behind the global economy and allows businesses to reach new markets and customers. <br/>  <br/> Aids to trade are any factors that make trading easier and more efficient. They include things like transportation, communication, and financial services. <br/>  <br/> By making it easier and more efficient to trade, trading and aids to trade can enlarge the scope of economic activities. This can lead to increased economic growth and development.</div>", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION"}, {"id": "objective>Commerce>2007>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The creation of utilities to satisfy human wants is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumption </div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrialization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">occupation </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Production can be defined as the creation of utility. It can also be defined as the transformation and conversion of raw materials into finished goods in order to satisfy human wants.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2007>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major criticism of a cooperative society is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">limited capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">granting excessive loans to members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">selling goods on credit to members </div>", "<div style=\"font-family:Cambria;font-size:17px;\">management incompetence</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cooperative societies are owned and democratically controlled by their members. This means that the members are responsible for electing the board of directors and for making decisions about the society. However, this can also lead to problems if the members are not qualified or experienced to manage the society.</div>", "topic": "BUSINESS UNIT: PARTNERSHIP : ADVANTAGES AND DISADVANTAGES"}, {"id": "objective>Commerce>2007>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An economic activity which deals with natural resources is a form of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">extraction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">refining </div>", "<div style=\"font-family:Cambria;font-size:17px;\">construction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Extractive industries are those who engage in obtaining raw materials and natural resources from the soil or sea.</div>", "topic": "OCCUPATION : TYPES OF OCCUPATION"}, {"id": "objective>Commerce>2007>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first stage in tourism planning is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">assessing feedback from tourists </div>", "<div style=\"font-family:Cambria;font-size:17px;\">preparing a list of tourist attractions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">creating recreational opportunities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">building community support </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This step involves understanding the existing tourism landscape, identifying key attractions, assessing infrastructure, and evaluating market trends. This foundational knowledge is critical for informed decision-making and strategic planning.</div>", "topic": "AIDS TO TRADE: TOURISM : TYPES & IMPORTANCE"}, {"id": "objective>Commerce>2007>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An agreement by the insurer to compensate the insured for losses suffered is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">surrender value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">caveat emptor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indemnity </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The  term indemnity insurance refers to an insurance policy that compensates an insured party policy that compensates an insured party for certain unexpected damages or losses up to a certain limit usually the amount of the loss itself.</div>", "topic": "AIDS TO TRADE: INSURANCE : TERMS"}, {"id": "objective>Commerce>2007>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the functions of the Nigeria Ports Authority is the provision of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">facilities to enhance the speedy loading and offloading of cargoes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">facilities to ensure that the goods get to their destination </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shelter for operators of cargoes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">courier services to ensure speedy delivery </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Ports Authority provides facilities to enhance the speedy loading and offloading of cargoes such as ports and warehouses.</div>", "topic": "TRADE ( 2) : CUSTOMS, EXCISE, PORTS AUTHORITY ETC."}, {"id": "objective>Commerce>2007>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The world tourism organization has its headquarters in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">New York</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Paris</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Madrid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">London</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The World Tourism Organization is the United Nations specialized agency entrusted with the provision of responsible, sustainable and universally accessible tourism,  having its headquarters in Madrid, Spain.</div>", "topic": "AIDS TO TRADE: TOURISM : AGENCIES THAT PROMOTE TOURISM & CHALLENGES OF TOURISM"}, {"id": "objective>Commerce>2007>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Digital computer is divided into </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">analoque, hybrid and mini</div>", "<div style=\"font-family:Cambria;font-size:17px;\">super, mainframe, mini and micro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mainframe, hybrid and micro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">super, mainframe, micro and analoque</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Digital computers are device that needs to be programmed in order to receive the desired output.  It uses electronic technology to generate, store and process different types of data. Based on the size and type of the device, digital computers are classified into four categories, which are: Microcomputer,Minicomputer, Mainframe computer, Supercomputer.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2007>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A distinctive advantage of GSM is its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mobility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coverage</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">GSM means Global System for <strong>Mobile</strong> Communication. The advantages are: <br/> - More suitable network with robust features <br/> - Easy mobility i,e can be carried about. <br/> - No roaming charges on international calls <br/> - provides high transmission quality <br/> -Has the ability to use repeaters  etc. </div>", "topic": "AIDS TO TRADE: COMMUNICATION : ADVANTAGES & DISADVANTAGES"}, {"id": "objective>Commerce>2007>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the permanent storage device, DASD means</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Data Access Storage Device</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Data Access Systems Device</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Direct Access System Device </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Direct Access Storage Device</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">DASD stands for Direct Access Storage Device. It is a type of secondary storage device that allows for direct access to data, meaning that the computer can access any part of the storage device without having to read through the entire device sequentially. This makes DASDs much faster and more efficient than sequential access storage devices, such as magnetic tape drives. <br/>  <br/> DASDs are used to store a wide variety of data, including operating systems, application software, user data, and databases. They are also used to store backup and recovery data.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TERMS IN COMPUTER"}, {"id": "objective>Commerce>2007>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major determinant of fire insurance premium is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">type and structure of the property to be insured</div>", "<div style=\"font-family:Cambria;font-size:17px;\">usefulness of the property to the owner</div>", "<div style=\"font-family:Cambria;font-size:17px;\">owner of the property to be insured</div>", "<div style=\"font-family:Cambria;font-size:17px;\">extent of fire damage anticipated</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The amount of insurance premium is influenced by the type, structure, location of the property. A part of these annual costs is determined by the insurance premium and the amount is influenced by the type of construction, the location, the structure and the use of the property..</div>", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES"}, {"id": "objective>Commerce>2007>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The internet is a system of telecommunication used for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">communicating long distance message </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sending and receiving text message </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sending electronic messages </div>", "<div style=\"font-family:Cambria;font-size:17px;\">communicating message through telegrams</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The internet is a system of telecommunication primarily used for sending electronic messages. This includes e-mails, instant messaging, and other forms of digital communication. While it can be used for long distance communication and sending text messages, these are specific uses of electronic messaging, making option 3 the most comprehensive and correct answer.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : MERITS & DEMERIT"}, {"id": "objective>Commerce>2007>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A written agreement for hiring a ship for transporting goods is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consular invoice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bill of landing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">charted party </div>", "<div style=\"font-family:Cambria;font-size:17px;\">certificate of origin </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Charter party is a contract whereby a ship or aircraft is temporarily leased by the owner to another person to transport cargoes from one place to another. The charterer pays charges called CHARTER. <br/> </div>", "topic": "AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION"}, {"id": "objective>Commerce>2007>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major function of trade association is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">liaises with foreign trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">help to promote foreign trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">facilitate members' access to credit facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">help to promote research on behalf of members</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Trade associations often engage in research activities to gather industry-specific data, market trends, and information relevant to their members. This research can help members make informed decisions, stay competitive, and navigate regulatory changes. While trade associations may also engage in activities related to foreign trade, promoting foreign trade, and facilitating access to credit facilities, their primary role often includes research and advocacy on behalf of their members' interests.</div>", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS"}, {"id": "objective>Commerce>2007>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major setback of international trade is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inadequate exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic sanctions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">devaluation of currency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange rate appreciation </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic sanctions placed on a particular country can hinder international trade. They are domestic penalties applied unilaterally by one country (or multilaterally, by a group of countries) on another country (or group of countries). Economic sanctions may include various forms of trade barriers and restrictions on financial transactions.</div>", "topic": "TRADE ( 2) : FOREIGN TRADE"}, {"id": "objective>Commerce>2007>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following requires payment into the payee's account?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">crossed cheque</div>", "<div style=\"font-family:Cambria;font-size:17px;\">traveller's cheque</div>", "<div style=\"font-family:Cambria;font-size:17px;\">open cheque</div>", "<div style=\"font-family:Cambria;font-size:17px;\">certified cheque</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Crossed cheque is a cheque with two parallel lines either across the whole cheque or through the top left-hand corner of the cheque. It is an instruction to the paying banker to transfer the specified amount from the payer account and not over the counter.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2007>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The traditional way of paying cooperative dividend is to distribute profit in proportion to members'</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">subscriptions </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total savings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">volume of purchase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">contributions</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a cooperative, the traditional way of paying dividends is to distribute profit in proportion to members' volume of purchase. This means that the more a member purchases from the cooperative, the higher their share of the profit. This is done to encourage members to purchase more from the cooperative, thereby increasing the cooperative's sales and profits.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2007>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The abbreviation C and F indicates that the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">production cost exclude the cost of carriage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">selling price includes the cost of carriage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost of production includes delivering charges </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost of production includes the cost of carriage </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">C & F stands for cost and freight and it means that the seller must pay the costs and freight necessary to bring the goods to a named port of destination and must also procure marine insurance against the buyer's risk or loss to the goods during the carriage. </div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>2007>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sales of foreign investment and gold reserves can be used to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">correct adverse balance of trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase invisible import </div>", "<div style=\"font-family:Cambria;font-size:17px;\">correct adverse balance of payments </div>", "<div style=\"font-family:Cambria;font-size:17px;\">correct a budget deficit </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Balance of payments is a record of all transactions made between one particular country and all other countries during a specified period of time. It compares the dollar difference of the amount of exports and imports, including all financial exports and imports. A negative balance of payments means that more money is flowing out of the country than coming in, and vice versa.</div>", "topic": "TRADE ( 2) : BALANCE OF PAYMENT"}, {"id": "objective>Commerce>2007>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A share premium is an example of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">issued capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital stock</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equity capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital reserve </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Share premium is the amount by which the amount received by a company for a stock issue exceeds its face value. It is an example of capital reserve.</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2007>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major benefit a debtor can derive from using a credit facility is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">better service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">goodwill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">convenience </div>", "<div style=\"font-family:Cambria;font-size:17px;\">control</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The advantages of credit are: <br/> - increase in sales <br/> - increase in profit <br/> - encouragement of bulk <br/> - enjoyment of goods without payment <br/> - increase standard of living etc</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : ADVANTAGES AND DISADVATAGES"}, {"id": "objective>Commerce>2007>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The function of money that facilitates the comparison of the quantity of goods as a basis of exchange is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unit of account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">measure of value</div>", "<div style=\"font-family:Cambria;font-size:17px;\">store of value </div>", "<div style=\"font-family:Cambria;font-size:17px;\">medium of exchange </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As a measure of value, the value of goods and services are expressed by prices,  therefore money is used as a yardstick to measure and compare the worth of goods and services as well as occupation.</div>", "topic": "MONEY : FUNCTIONS OF MONEY"}, {"id": "objective>Commerce>2007>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The difference between the buying and selling price of shares is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">brokerage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">margin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">jobber's turn </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gross profit </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dealers in the shares and stock are known as jobbers. Members of the public buy shares from jobber through brokers who serves as agent. They buy and sell shares in two prices, which are: <br/> -   Lower price: the buying price <br/> -  Higher price: the selling price. <br/> The difference between the two prices (Higher price less Lower price) is known as JOBBER'S TURN and this represent the profit of the jobber.</div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}, {"id": "objective>Commerce>2007>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is risk-free security?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">preference share</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ordinary share</div>", "<div style=\"font-family:Cambria;font-size:17px;\">treasury bill</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debenture</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is a short-dated government security, yielding no interest but issued at a discount on its redemption price.</div>", "topic": "STOCK EXCHANGE : TYPES OF SECURITIES"}, {"id": "objective>Commerce>2007>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Central Bank controls the quantity of money in circulation through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">open market operation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the tax rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">issuing new currencies </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the tax rate </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An open market operation (OMO) is an activity by a central bank to buy or sell government bonds on the open market. A Central Bank uses them as the primary means of implementing monetary policy.</div>", "topic": "MONEY : MEANING AND TYPES OF MONEY"}, {"id": "objective>Commerce>2007>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The selling of new shares to existing shareholders is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public issue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offer for sate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">right issue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bonus issue</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The selling of new shares to existing shareholders is referred to as a rights issue. A rights issue is a way for companies to raise capital. The company gives shareholders a chance to purchase additional shares in the company in proportion to their existing holdings, at a discounted price. Public issue, offer for sale, and bonus issue are different methods of issuing shares or raising capital.</div>", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS"}, {"id": "objective>Commerce>2007>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A new company requiring a large amount of equity finance may source funds from the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">central bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">money market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">commercial banks</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A new company requiring a large amount of equity finance may source funds from the capital market. The capital market is a market for securities (debt or equity), where business enterprises (companies) and governments can raise long-term funds. It is defined as a market in which money is provided for periods longer than a year.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2007>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A credit-instrument which also serves as a legal tender is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cheque</div>", "<div style=\"font-family:Cambria;font-size:17px;\">paper money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">voucher</div>", "<div style=\"font-family:Cambria;font-size:17px;\">money order </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Paper money is a country's official paper currency that is circulated for the transactions involved in acquiring goods and services.</div>", "topic": "MONEY : MEANING AND TYPES OF MONEY"}, {"id": "objective>Commerce>2007>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question  <br/>  Balance Sheet of XYZ as at 31/12/2003 <br/>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Ordinary share capital</td><td style=\"border:1px solid black;text-align:center;\"> 25 000 000</td><td style=\"border:1px solid black;text-align:center;\"> Fixed assets</td><td style=\"border:1px solid black;text-align:center;\"> 26 000 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Revenue reserve</td><td style=\"border:1px solid black;text-align:center;\"> 10 000 000</td><td style=\"border:1px solid black;text-align:center;\"> Investment</td><td style=\"border:1px solid black;text-align:center;\"> 22 000 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General reserve</td><td style=\"border:1px solid black;text-align:center;\"> 3 000 000</td><td style=\"border:1px solid black;text-align:center;\"> Current assets</td><td style=\"border:1px solid black;text-align:center;\"> 5 000 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Long term liabilities</td><td style=\"border:1px solid black;text-align:center;\"> 4 000 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Current liabilities</td><td style=\"border:1px solid black;text-align:center;\"> 11 000 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 53 000 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 53 000 000</td></tr></table></div> <br/>  <br/> What is the net working capital</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">(₦6,000,000)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦16,000,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦11,000,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦8,000,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The net working capital = current assets - current liabilities  <br/>                      =5000000 - 11000000  <br/>                        =  - 6,000,000 <br/> Note that ( ) means Minus (-) in accounting i.e deficit <br/> Therefore the answer is (#6,000,000)</div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2007>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question  <br/>  Balance Sheet of XYZ as at 31/12/2003 <br/>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Ordinary share capital</td><td style=\"border:1px solid black;text-align:center;\"> 25 000 000</td><td style=\"border:1px solid black;text-align:center;\"> Fixed assets</td><td style=\"border:1px solid black;text-align:center;\"> 26 000 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Revenue reserve</td><td style=\"border:1px solid black;text-align:center;\"> 10 000 000</td><td style=\"border:1px solid black;text-align:center;\"> Investment</td><td style=\"border:1px solid black;text-align:center;\"> 22 000 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">General reserve</td><td style=\"border:1px solid black;text-align:center;\"> 3 000 000</td><td style=\"border:1px solid black;text-align:center;\"> Current assets</td><td style=\"border:1px solid black;text-align:center;\"> 5 000 000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Long term liabilities</td><td style=\"border:1px solid black;text-align:center;\"> 4 000 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Current liabilities</td><td style=\"border:1px solid black;text-align:center;\"> 11 000 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 53 000 000</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 53 000 000</td></tr></table></div> <br/> Determine the owners' equity</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦38,000,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20,000,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦42,000,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦25,000,000</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Owner's equity = ordinary share capital + revenue reserve + general reserve  <br/>  = ₦(25,000,000 + 10,000,000 + 3,000,000)  <br/>  = ₦38,000,000 </div>", "topic": "FINANCING BUSINESS : TYPES OF CAPITAL"}, {"id": "objective>Commerce>2007>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The body regulating the sale and purchase of shares in Nigeria is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Corporate Affairs commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Securities and Exchange Commission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Securities and Exchange Tribunal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria Stock Exchange</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Security and Exchange Commission (SEC) is the apex regulatory institution of the Nigerian Capital market supervised by the Federal Ministry of Finance and founded in 1979. The Nigerian Stock Exchange (NSE) is privately owned and self regulating, but the NSE is regulated by the SEC. <br/> </div>", "topic": "STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS"}];
